import React, { useState } from "react";
import {
    FacebookShareButton,
    TwitterShareButton,
    LinkedinShareButton,
    WhatsappShareButton,
    FacebookIcon,
    TwitterIcon,
    LinkedinIcon,
    WhatsappIcon,
} from "react-share";
import { X, Link, Check, Copy, Instagram } from "lucide-react";

export default function ShareModal({ isOpen, onClose, post, currentUser }) {
    const [copied, setCopied] = useState(false);

    if (!isOpen) return null;

    const shareUrl = `${window.location.origin}/post/${post.id}`;
    const shareTitle = post.content || `${currentUser?.name || "User"} shared a post on Capavate`;

    const copyToClipboard = async () => {
        try {
            await navigator.clipboard.writeText(shareUrl);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch {
            console.error("Failed to copy");
        }
    };

    // Custom Instagram share handler
    const handleInstagramShare = () => {
        // Instagram doesn't have direct web share API
        // Copy link and show instructions
        copyToClipboard();

        // Try to open Instagram app on mobile
        const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
        if (isMobile) {
            // For mobile, try to open Instagram app
            window.location.href = "instagram://library?AssetPath=" + encodeURIComponent(shareUrl);

            // Fallback after 1 second if app doesn't open
            setTimeout(() => {
                window.open("https://www.instagram.com", "_blank");
            }, 1000);
        } else {
            // For desktop, open Instagram web
            window.open("https://www.instagram.com", "_blank");
            alert("Link copied! You can now paste it in your Instagram post or story.");
        }
    };

    const shareOptions = [
        {
            name: "Facebook",
            component: FacebookShareButton,
            icon: FacebookIcon,
            color: "#1877f2",
            bgColor: "#eaf3ff",
            props: { hashtag: "#Capavate" },
        },
        {
            name: "Twitter",
            component: TwitterShareButton,
            icon: TwitterIcon,
            color: "#1da1f2",
            bgColor: "#e8f5fd",
            props: { title: shareTitle, hashtags: ["Capavate"] },
        },
        {
            name: "LinkedIn",
            component: LinkedinShareButton,
            icon: LinkedinIcon,
            color: "#0077b5",
            bgColor: "#eaf4f8",
            props: { title: shareTitle },
        },
        {
            name: "WhatsApp",
            component: WhatsappShareButton,
            icon: WhatsappIcon,
            color: "#25d366",
            bgColor: "#e8f9ef",
            props: { title: shareTitle },
        },
        {
            name: "Instagram",
            component: null,
            icon: Instagram,
            color: "#E4405F",
            bgColor: "#fef2f4",
            onClick: handleInstagramShare,
            isCustom: true,
        },
    ];

    return (
        <>
            {/* Backdrop */}
            <div
                onClick={onClose}
                style={{
                    position: "fixed", inset: 0,
                    backgroundColor: "rgba(0,0,0,0.55)",
                    backdropFilter: "blur(4px)",
                    zIndex: 9999,
                    animation: "fadeIn 0.2s ease-out",
                }}
            />

            {/* Modal */}
            <div style={{
                position: "fixed",
                top: "50%", left: "50%",
                transform: "translate(-50%, -50%)",
                width: "90%", maxWidth: 520,
                backgroundColor: "#fff",
                borderRadius: 24,
                boxShadow: "0 20px 60px rgba(0,0,0,0.25)",
                zIndex: 10000,
                overflow: "hidden",
                animation: "slideUp 0.3s ease-out",
            }}>

                {/* Header */}
                <div style={{
                    padding: "20px 24px",
                    borderBottom: "1px solid #f0f0f0",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                }}>
                    <div>
                        <h5 style={{ margin: 0, fontSize: "1.1rem", fontWeight: 700, color: "#1a1a1a" }}>
                            Share Post
                        </h5>
                        <p style={{ margin: "3px 0 0", fontSize: "0.78rem", color: "#999" }}>
                            Share this post with your network
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        style={{
                            width: 34, height: 34, borderRadius: "50%",
                            border: "none", backgroundColor: "#f5f5f5",
                            cursor: "pointer", display: "flex",
                            alignItems: "center", justifyContent: "center",
                        }}
                        onMouseEnter={(e) => e.currentTarget.style.backgroundColor = "#ebebeb"}
                        onMouseLeave={(e) => e.currentTarget.style.backgroundColor = "#f5f5f5"}
                    >
                        <X size={18} color="#666" />
                    </button>
                </div>

                {/* Post preview */}
                <div style={{ margin: "16px 24px", padding: 14, backgroundColor: "#f8f9fa", borderRadius: 14, border: "1px solid #eef2f6" }}>
                    <div style={{ display: "flex", gap: 10, alignItems: "flex-start" }}>
                        {/* Avatar */}
                        <div style={{
                            width: 38, height: 38, borderRadius: "50%",
                            backgroundColor: "#ff3e43",
                            display: "flex", alignItems: "center", justifyContent: "center",
                            color: "#fff", fontWeight: 700, fontSize: "0.95rem", flexShrink: 0,
                            overflow: "hidden",
                        }}>
                            {post.author_image ? (
                                <img src={post.author_image} alt="author" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                            ) : (
                                (post.author_name || post.name || "?").charAt(0).toUpperCase()
                            )}
                        </div>
                        <div style={{ flex: 1 }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
                                <span style={{ fontWeight: 600, fontSize: "0.85rem", color: "#1a1a1a" }}>
                                    {post.author_name || post.name || "User"}
                                </span>
                                <span style={{
                                    fontSize: "0.65rem", padding: "1px 7px", borderRadius: 10,
                                    backgroundColor: post.author_type === "company" ? "#fff3e0" : "#e8f5e9",
                                    color: post.author_type === "company" ? "#e65100" : "#2e7d32",
                                    border: `1px solid ${post.author_type === "company" ? "#ffcc80" : "#a5d6a7"}`,
                                    fontWeight: 600,
                                }}>
                                    {post.author_type === "company" ? "🏢 Company" : "👤 Investor"}
                                </span>
                            </div>
                            {post.content && (
                                <p style={{
                                    margin: 0, fontSize: "0.8rem", color: "#555", lineHeight: 1.45,
                                    display: "-webkit-box", WebkitLineClamp: 2,
                                    WebkitBoxOrient: "vertical", overflow: "hidden",
                                }}>
                                    {post.content}
                                </p>
                            )}
                            {post.images?.length > 0 && (
                                <div style={{
                                    marginTop: 8, width: "100%", height: 100, borderRadius: 10,
                                    backgroundImage: `url(${post.images[0]})`,
                                    backgroundSize: "cover", backgroundPosition: "center",
                                    backgroundColor: "#eef2f6",
                                }} />
                            )}
                        </div>
                    </div>
                </div>

                {/* Platform buttons */}
                <div style={{ padding: "0 24px 20px" }}>
                    <p style={{ fontSize: "0.8rem", fontWeight: 600, color: "#555", marginBottom: 12 }}>
                        Choose platform
                    </p>
                    <div style={{
                        display: "grid",
                        gridTemplateColumns: "repeat(5, 1fr)",
                        gap: 10,
                    }}>
                        {shareOptions.map((opt) => {
                            // For Instagram (custom button)
                            if (opt.isCustom) {
                                const Icon = opt.icon;
                                return (
                                    <div
                                        key={opt.name}
                                        onClick={opt.onClick}
                                        style={{
                                            display: "flex", flexDirection: "column",
                                            alignItems: "center", gap: 6,
                                            padding: "10px 4px", borderRadius: 12,
                                            backgroundColor: opt.bgColor,
                                            transition: "all 0.2s", cursor: "pointer",
                                        }}
                                        onMouseEnter={(e) => {
                                            e.currentTarget.style.transform = "translateY(-2px)";
                                            e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.1)";
                                        }}
                                        onMouseLeave={(e) => {
                                            e.currentTarget.style.transform = "translateY(0)";
                                            e.currentTarget.style.boxShadow = "none";
                                        }}
                                    >
                                        <Icon size={36} strokeWidth={1.5} color={opt.color} />
                                        <span style={{ fontSize: "0.68rem", fontWeight: 500, color: opt.color }}>
                                            {opt.name}
                                        </span>
                                    </div>
                                );
                            }

                            // For other platforms (Facebook, Twitter, LinkedIn, WhatsApp)
                            const Btn = opt.component;
                            const Icon = opt.icon;
                            return (
                                <Btn key={opt.name} url={shareUrl} {...opt.props}>
                                    <div
                                        style={{
                                            display: "flex", flexDirection: "column",
                                            alignItems: "center", gap: 6,
                                            padding: "10px 4px", borderRadius: 12,
                                            backgroundColor: opt.bgColor,
                                            transition: "all 0.2s", cursor: "pointer",
                                        }}
                                        onMouseEnter={(e) => {
                                            e.currentTarget.style.transform = "translateY(-2px)";
                                            e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.1)";
                                        }}
                                        onMouseLeave={(e) => {
                                            e.currentTarget.style.transform = "translateY(0)";
                                            e.currentTarget.style.boxShadow = "none";
                                        }}
                                    >
                                        <Icon size={36} round />
                                        <span style={{ fontSize: "0.68rem", fontWeight: 500, color: opt.color }}>
                                            {opt.name}
                                        </span>
                                    </div>
                                </Btn>
                            );
                        })}
                    </div>
                </div>

                {/* Copy link */}
                <div style={{
                    padding: "16px 24px 24px",
                    borderTop: "1px solid #f0f0f0",
                    backgroundColor: "#fafafa",
                }}>
                    <p style={{ fontSize: "0.8rem", fontWeight: 600, color: "#555", marginBottom: 10 }}>
                        Or copy link
                    </p>
                    <div style={{ display: "flex", gap: 10 }}>
                        <div style={{
                            flex: 1, display: "flex", alignItems: "center", gap: 8,
                            padding: "9px 14px", backgroundColor: "#fff",
                            border: "1px solid #e0e0e0", borderRadius: 12,
                        }}>
                            <Link size={14} color="#bbb" />
                            <input
                                type="text"
                                value={shareUrl}
                                readOnly
                                style={{
                                    flex: 1, border: "none", outline: "none",
                                    fontSize: "0.78rem", color: "#777",
                                    backgroundColor: "transparent",
                                }}
                            />
                        </div>
                        <button
                            onClick={copyToClipboard}
                            style={{
                                display: "flex", alignItems: "center", gap: 6,
                                padding: "9px 18px", borderRadius: 12, border: "none",
                                backgroundColor: copied ? "#4caf50" : "#ff3e43",
                                color: "#fff", cursor: "pointer",
                                fontWeight: 600, fontSize: "0.8rem",
                                transition: "all 0.2s", whiteSpace: "nowrap",
                            }}
                        >
                            {copied ? <><Check size={14} /> Copied!</> : <><Copy size={14} /> Copy</>}
                        </button>
                    </div>
                </div>
            </div>

            <style>{`
                @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
                @keyframes slideUp {
                    from { opacity: 0; transform: translate(-50%, -42%); }
                    to   { opacity: 1; transform: translate(-50%, -50%); }
                }
            `}</style>
        </>
    );
}